export class ApiException extends Error {
  override message: string;
  status: number;
  response: string;
  headers: { [key: string]: any };
  result: any;

  constructor(
    message: string,
    status: number,
    response: string,
    headers: { [key: string]: any },
    result: any,
  ) {
    super();

    this.message = message;
    this.status = status;
    this.response = response;
    this.headers = headers;
    this.result = result;
  }

  protected isApiException = true;

  static isApiException(obj: any): obj is ApiException {
    return obj.isApiException === true;
  }
}

function throwException(
  message: string,
  status: number,
  response: string,
  headers: { [key: string]: any },
  result?: any,
): Observable<any> {
  if (result !== null && result !== undefined) return _observableThrow(result);
  else return _observableThrow(new ApiException(message, status, response, headers, null));
}

function blobToText(blob: any): Observable<string> {
  return new Observable<string>((observer) => {
    try {
      if (!blob) {
        observer.next('');
        observer.complete();
        return;
      }

      if (typeof blob === 'string') {
        observer.next(blob);
        observer.complete();
        return;
      }

      if (blob instanceof ArrayBuffer || ArrayBuffer.isView(blob)) {
        const bytes = blob instanceof Uint8Array ? blob : new Uint8Array(blob as ArrayBufferLike);

        observer.next(new TextDecoder().decode(bytes));
        observer.complete();
        return;
      }

      if (typeof blob?.text === 'function') {
        blob
          .text()
          .then((text: string) => {
            observer.next(text);
            observer.complete();
          })
          .catch((err: any) => observer.error(err));
        return;
      }

      observer.next(typeof blob === 'object' ? JSON.stringify(blob) : String(blob));
      observer.complete();
    } catch (err) {
      observer.next(String(err));
      observer.complete();
    }
  });
}
